import{_ as a,o as s,c as n,ae as i}from"./chunks/framework.D8e0q88G.js";const k=JSON.parse('{"title":"Viewport","description":"","frontmatter":{},"headers":[],"relativePath":"frontend/viewport.md","filePath":"frontend/viewport.md"}'),t={name:"frontend/viewport.md"};function o(r,e,l,p,d,c){return s(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="viewport" tabindex="-1">Viewport <a class="header-anchor" href="#viewport" aria-label="Permalink to &quot;Viewport&quot;">​</a></h1><p><strong>File:</strong> <code>frontend/src/components/dashboard/viewport/Viewport.tsx</code></p><p>The Viewport is the central orchestrator of the application. It manages video playback, hosts all canvas overlays, triggers pose inference, and publishes computed metrics to <code>VideoContext</code> for the Telemetry panel to consume.</p><h2 id="responsibilities" tabindex="-1">Responsibilities <a class="header-anchor" href="#responsibilities" aria-label="Permalink to &quot;Responsibilities&quot;">​</a></h2><ul><li><strong>Video loading</strong> — accepts a user-selected file, probes its true FPS using FFmpeg.js (browser metadata is unreliable), and sets up an <code>&lt;video&gt;</code> element</li><li><strong>Playback control</strong> — frame-by-frame stepping, variable speed (1/16×–4×), seek bar, zoom/pan transforms (1×–8×)</li><li><strong>Pose inference</strong> — invokes <code>usePoseLandmarker</code> to POST the video to the backend and receive keypoints</li><li><strong>Overlay management</strong> — renders <code>PoseOverlay</code>, <code>CalibrationOverlay</code>, <code>MeasurementOverlay</code>, and <code>CropOverlay</code> on stacked canvases</li><li><strong>Manual contact annotation</strong> — lets the user click to place ground contact events that the algorithm missed or got wrong</li><li><strong>Sprint markers</strong> — frame-accurate start and finish markers for both static and flying timing modes</li><li><strong>Metric publication</strong> — calls <code>useSprintMetrics</code> and writes the result into <code>VideoContext</code></li><li><strong>Export</strong> — passes video + overlay data to FFmpeg.js for trimmed/cropped MP4 export</li></ul><h2 id="overlay-stack" tabindex="-1">Overlay Stack <a class="header-anchor" href="#overlay-stack" aria-label="Permalink to &quot;Overlay Stack&quot;">​</a></h2><p>Overlays are absolutely positioned canvases stacked on top of the video:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────┐</span></span>
<span class="line"><span>│  &lt;video&gt;                    │  base layer — playback</span></span>
<span class="line"><span>├─────────────────────────────┤</span></span>
<span class="line"><span>│  PoseOverlay (canvas)       │  skeleton + keypoints</span></span>
<span class="line"><span>├─────────────────────────────┤</span></span>
<span class="line"><span>│  CalibrationOverlay (canvas)│  reference line drawing</span></span>
<span class="line"><span>├─────────────────────────────┤</span></span>
<span class="line"><span>│  MeasurementOverlay (canvas)│  freehand measurements</span></span>
<span class="line"><span>├─────────────────────────────┤</span></span>
<span class="line"><span>│  CropOverlay (canvas)       │  crop region selection</span></span>
<span class="line"><span>└─────────────────────────────┘</span></span></code></pre></div><p>Only one overlay is active (interactive) at a time. A mode enum controls which overlay receives pointer events.</p><h2 id="zoom-and-pan" tabindex="-1">Zoom and Pan <a class="header-anchor" href="#zoom-and-pan" aria-label="Permalink to &quot;Zoom and Pan&quot;">​</a></h2><p>The entire overlay stack is wrapped in a <code>transform: scale(zoom) translate(panX, panY)</code> CSS transform. All overlay canvases share the same transform, so they stay aligned regardless of zoom level.</p><p>Pointer coordinates from any overlay must be transformed back to video-space coordinates before use:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> videoX</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (pointerX </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> panX) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> zoom;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> videoY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (pointerY </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> panY) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> zoom;</span></span></code></pre></div><h2 id="fps-probing" tabindex="-1">FPS Probing <a class="header-anchor" href="#fps-probing" aria-label="Permalink to &quot;FPS Probing&quot;">​</a></h2><p>Browser <code>video.duration</code> and <code>video.videoWidth/Height</code> are reliable, but <code>currentTime</code> stepping to measure frame rate is not. SprintLab uses FFmpeg.js to probe the container metadata and extract the true frame rate before any analysis begins. This matters for velocity and acceleration calculations — a 10% FPS error produces a 10% error in all angular velocity values.</p><h2 id="playback-loop" tabindex="-1">Playback Loop <a class="header-anchor" href="#playback-loop" aria-label="Permalink to &quot;Playback Loop&quot;">​</a></h2><p>Playback is driven by <code>requestAnimationFrame</code>. At each tick:</p><ol><li>The video&#39;s <code>currentTime</code> is advanced by <code>1/fps * speed</code></li><li>The current frame index is computed: <code>Math.round(currentTime * fps)</code></li><li><code>VideoContext.setFrame(frameIdx)</code> is called</li><li>All overlays re-render for the new frame</li></ol><p>This makes the frame index the single source of truth — the Telemetry panel updates its playhead by reading <code>VideoContext.frame</code>.</p>`,19)])])}const m=a(t,[["render",o]]);export{k as __pageData,m as default};
